import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ActivityLevel {
  day: string;
  activity: number;
}

interface PetCareData {
  feedingSchedule: {
    nextFeeding: string;
    foodType: string;
    amount: string;
  };
  vetAppointment: {
    date: string;
    time: string;
    vetName: string;
    location: string;
  };
  activityLevel: ActivityLevel[];
}

export default function Widget() {
  const petData = response.data as PetCareData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={3}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Next Feeding
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FFB74D' }}>
              {petData.feedingSchedule.nextFeeding}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {`${petData.feedingSchedule.foodType} - ${petData.feedingSchedule.amount}`}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Vet Appointment
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#8D6E63' }}>
              {`${petData.vetAppointment.date} at ${petData.vetAppointment.time}`}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {`${petData.vetAppointment.vetName} - ${petData.vetAppointment.location}`}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: petData.activityLevel.map(a => a.activity),
                  color: '#FFB74D',
                  label: 'Activity Level',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: petData.activityLevel.map(a => a.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'activity' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="activity"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
